CREATE PROCEDURE [dbo].[CalculateTrimmedMeanProc]
@values NVARCHAR (MAX) NULL
AS EXTERNAL NAME [Database1].[StoredProcedures].[CalculateTrimmedMeanProc]

EXEC dbo.CalculateTrimmedMeanProc @values = '10, 20, 30, 40, 100';
EXEC dbo.CalculateTrimmedMeanProc @values = '5 15 25 35 999';
EXEC dbo.CalculateTrimmedMeanProc @values = '1,2,3,4,5,6,1000';